import{_ as a,c as s,g as t,o as n}from"./chunks/framework.CCxIPCIe.js";const _=JSON.parse('{"title":"四一三","description":"","frontmatter":{"title":"四一三","date":"2023-03-17T12:34:42.694Z","length":"351字","time":"2分钟","aside":false,"hash":-255260065},"headers":[],"relativePath":"idea/413.md","filePath":"idea/413.md"}'),r={name:"idea/413.md"};function o(d,e,i,l,p,c){return n(),s("div",null,e[0]||(e[0]=[t("p",null,"数学的本质是什么？是计算。说起计算，很多人的第一印象是枯燥而繁琐。抽象符号之间的变换本身是乏味的，只有当它为着一个目的服务时，才能体现出某种意义。这个目的就是归约。归约是对信息的揭示和澄清，所谓的数学之美正源于此。透过这种归约人们能理解纷繁芜杂的现象世界背后的本质，领略这种本质，激发了如同好好色般对朴素的美的感受，这才把这种明显由高级认识产生的审美体验称之为“自然之美”。 脱离这种归约，在逻辑上公式只是同义反复。正如连通器的两端是静止的水平。",-1),t("p",null,"学习数学往往执着于微观却忽略了宏观。即执着于推导的正确性（证明），却轻视了动机（定理链条）。说得直白些，数学证明作为演绎逻辑，至多是充分必要。充分必要从微观上看就是同义反复，缺乏动机说的再多也是废话连篇。 这就好比稳态热力学系统微观上步步可逆，但是宏观上却从有序向无序演进。数学逻辑也必须在推理上保证正确的同时，从无序向有序演进。",-1)]))}const f=a(r,[["render",o]]);export{_ as __pageData,f as default};
